n3 = inputs.get('node_3') or {}
n3b = inputs.get('node_3b') or {}
trig = inputs.get('trigger') or {}
intent = (n3.get('intents') or ['unknown'])[0]
ents = n3b.get('entities') or {}
user_role = trig.get('user_role', 'business')
needs_id_intents = ('diagnostics', 'remediation')
has_an_id = any(ents.get(k) for k in ('request_id', 'agent_id', 'workflow_id'))
# Only fire NEED_INFO for business users on intents that need an id.
# Tech users shouldn't be paused — they can use the diagnostics fallback path.
needs_info = (intent in needs_id_intents) and (not has_an_id) and (user_role == 'business')
output = {'needs_info': needs_info, 'flag': 'ask' if needs_info else 'proceed', 'detected_intent': intent}

rem = inputs.get('node_8') or {}
iters = rem.get('iterations') or []
destructive = ('restart_service','rerun','terminate','rotate_credentials','change_schedule','assign_workflow','start_service','stop_service')
did_destructive = False
destructive_target = None
for it in iters:
    for tc in (it.get('tool_calls') or []):
        nm = (tc.get('name') or '').lower()
        if any(d in nm for d in destructive):
            did_destructive = True
            args = tc.get('arguments') or {}
            destructive_target = args.get('agent_id') or args.get('request_id') or args.get('workflow_id')
            break
    if did_destructive: break
output = {'did_destructive': did_destructive, 'flag': 'yes' if did_destructive else 'no', 'destructive_target': destructive_target}

om1 = inputs.get('node_om1') or {}
j = om1.get('json') or {}
wf = (j.get('match') or {}).get('workflow_id')
output = {'has_match': bool(wf), 'flag': 'matched' if wf else 'unmatched'}
